importScripts('https://www.gstatic.com/firebasejs/10.12.0/firebase-app-compat.js')
importScripts('https://www.gstatic.com/firebasejs/10.12.0/firebase-messaging-compat.js')

firebase.initializeApp({
  apiKey: '{{API_KEY}}',
  authDomain: '{{AUTH_DOMAIN}}',
  projectId: '{{PROJECT_ID}}',
  storageBucket: '{{STORAGE_BUCKET}}',
  messagingSenderId: '{{MESSAGING_SENDER_ID}}',
  appId: '{{APP_ID}}'
})

const messaging = firebase.messaging()

/**
 * Resolve a URL from an FCM payload to an absolute URL.
 * Handles both absolute URLs (external links) and relative paths (in-app routes).
 */
function resolveUrl(payload, defaultPath) {
  var path = (payload.data && payload.data.action_url)
    || (payload.data && payload.data.url)
    || (payload.data && payload.data.route)
    || (payload.data && payload.data.click_action)
    || (payload.fcmOptions && payload.fcmOptions.link)
    || defaultPath || '/'

  try {
    // Already an absolute URL (external or same-origin)
    if (path.startsWith('http://') || path.startsWith('https://')) {
      return path
    }
    // Relative path — resolve against service worker origin
    return new URL(path, self.location.origin).href
  } catch (e) {
    console.error('[pushfire] Failed to resolve URL:', path, e)
    return self.location.origin + '/'
  }
}

/**
 * Check if a URL is within the same origin as the service worker.
 */
function isSameOrigin(url) {
  try {
    return new URL(url).origin === self.location.origin
  } catch (e) {
    return false
  }
}

// ── Background Message Handler ──────────────────────────────────────────────
messaging.onBackgroundMessage(function (payload) {
  console.log('[pushfire] Background message received:', payload)

  var title = (payload.notification && payload.notification.title)
    || (payload.data && payload.data.title)
    || 'New Notification'

  var body = (payload.notification && payload.notification.body)
    || (payload.data && payload.data.body)
    || ''

  var icon = (payload.notification && payload.notification.icon)
    || (payload.data && payload.data.icon)
    || '/icon.png'

  // Resolve icon path to absolute URL
  if (icon && !icon.startsWith('http')) {
    icon = new URL(icon, self.location.origin).href
  }

  var url = resolveUrl(payload, '/')

  var options = {
    body: body,
    icon: icon,
    badge: '/badge.png',
    tag: 'pushfire-' + Date.now(),
    renotify: false,
    data: Object.assign({}, payload.data || {}, { __cp_url: url })
  }

  return self.registration.showNotification(title, options)
})

// ── Notification Click Handler ──────────────────────────────────────────────
// Handles both same-origin navigation and cross-origin URL opening.
// Safari-compatible: uses clients.openWindow() as fallback since
// client.navigate() may not be available in all Safari versions.
self.addEventListener('notificationclick', function (event) {
  console.log('[pushfire] Notification clicked:', event.notification.title)

  event.notification.close()

  var urlToOpen = (event.notification.data && event.notification.data.__cp_url)
    || self.location.origin + '/'

  console.log('[pushfire] Redirecting to:', urlToOpen)

  event.waitUntil(
    clients.matchAll({ type: 'window', includeUncontrolled: true }).then(function (clientList) {
      var sameOrigin = isSameOrigin(urlToOpen)

      if (sameOrigin) {
        // Try to find an existing tab at the same origin
        for (var i = 0; i < clientList.length; i++) {
          var client = clientList[i]
          try {
            if (new URL(client.url).origin === self.location.origin && 'focus' in client) {
              // Try navigate (not supported in all Safari versions)
              if (typeof client.navigate === 'function') {
                return client.navigate(urlToOpen).then(function () {
                  return client.focus()
                }).catch(function () {
                  // navigate() failed — fallback to openWindow
                  if (clients.openWindow) {
                    return clients.openWindow(urlToOpen)
                  }
                })
              } else {
                // No navigate support (older Safari) — focus and let the app handle routing
                return client.focus()
              }
            }
          } catch (e) {
            console.error('[pushfire] Tab navigation error:', e)
          }
        }
      }

      // No existing tab found, or URL is cross-origin — open a new window
      if (clients.openWindow) {
        return clients.openWindow(urlToOpen)
      }
    }).catch(function (err) {
      console.error('[pushfire] Click handler error:', err)
      // Last resort fallback
      if (clients.openWindow) {
        return clients.openWindow(urlToOpen)
      }
    })
  )
})
